solutions.javascript:
// Solution
function filterValidConfigurations(configs) {
  const pattern = /^([^:]+):([^:]+):([^:]+)$/;
  return configs.filter(config => {
    const match = config.match(pattern);
    if (!match) return false;
    const [_, hostPath, containerPath, permissions] = match;
    return ['ro', 'rw'].includes(permissions.toLowerCase());
  });
}
